const files = ($.steps.fetchCalendar.response && $.steps.fetchCalendar.response.files) ? $.steps.fetchCalendar.response.files : [];
const now = new Date();
const dayOfWeek = now.toLocaleDateString('en-US', { weekday: 'long' });
const dateStr = now.toISOString().split('T')[0];
const upcoming = [];
for (let i = 1; i <= 5; i++) {
  const d = new Date(now);
  d.setDate(d.getDate() + i);
  upcoming.push(d.toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' }));
}
const fileList = files.slice(0, 5).map(f => f.name + ' (modified: ' + (f.modifiedTime || 'unknown') + ')').join('\n');
return { dayOfWeek, dateStr, upcoming, fileList, fileCount: files.length };

const ctx = $.steps.buildContext.output;
const prompt = 'You are an executive scheduling assistant. Suggest optimal meeting slots for the following request.

MEETING: ' + $.input.meetingTitle + '
DURATION: ' + ($.input.duration || '30 minutes') + '
PREFERENCES: ' + ($.input.preferences || 'No specific preferences') + '
TODAY: ' + ctx.dayOfWeek + ', ' + ctx.dateStr + '
UPCOMING DAYS: ' + ctx.upcoming.join(', ') + '

CALENDAR FILES FOUND: ' + ctx.fileCount + '
' + ctx.fileList + '

Suggest 3-5 optimal time slots across the next 5 business days. For each slot provide:
- Date and time
- Why this slot is good
- Confidence level (high/medium/low)

Return ONLY valid JSON:
{
  "slots": [
    { "date": "...", "time": "...", "reason": "...", "confidence": "high" }
  ],
  "summary": "Brief scheduling recommendation"
}';
return { prompt };

let raw = $.steps.aiSuggest.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { text: raw }; }

const ai = $.steps.parseAI.output;
const title = $.input.meetingTitle;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':calendar: Meeting Scheduler: ' + title, emoji: true } });
if (ai.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.summary } });
}
blocks.push({ type: 'divider' });
const slots = ai.slots || [];
slots.forEach(function(slot, i) {
  var confidence = slot.confidence || 'medium';
  var emoji = confidence === 'high' ? ':large_green_circle:' : (confidence === 'medium' ? ':large_yellow_circle:' : ':white_circle:');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: emoji + ' *Slot ' + (i + 1) + ': ' + (slot.date || '') + ' at ' + (slot.time || '') + '*\n' + (slot.reason || '') } });
});
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':robot_face: Suggested by Claude AI | Duration: ' + ($.input.duration || '30 minutes') }] });
var fallback = 'Meeting Scheduler: ' + title + ' - ' + slots.length + ' slots suggested';
if (ai.text) { fallback = ai.text.slice(0, 500); }
return { blocks, fallback };
